<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>💰 PROFIT — Command Dashboard</title>
<style>
*{margin:0;padding:0;box-sizing:border-box}
:root{
  --bg:#0D1117;
  --panel:#1A1A2E;
  --border:#2A2A4A;
  --gold:#FFB347;
  --pink:#FF2D78;
  --cyan:#00D4FF;
  --green:#2ecc71;
  --red:#e74c3c;
  --dim:#666;
}
body{background:var(--bg);color:#ddd;font-family:Georgia,serif;max-width:640px;margin:0 auto;padding:8px;min-height:100vh}
.panel{
  background:var(--panel);
  background-image:
    linear-gradient(rgba(0,212,255,.03) 1px, transparent 1px),
    linear-gradient(90deg, rgba(0,212,255,.03) 1px, transparent 1px);
  background-size:20px 20px;
  border:1px solid var(--border);
  border-radius:8px;
  padding:14px;
  margin-bottom:10px;
  animation:breathe 4s ease-in-out infinite;
}
@keyframes breathe{0%,100%{box-shadow:0 0 4px rgba(255,179,71,.12)}50%{box-shadow:0 0 14px rgba(255,179,71,.25)}}
@keyframes ticker{from{transform:translateX(0)}to{transform:translateX(-50%)}}
@keyframes pulse{0%,100%{opacity:.85}50%{opacity:1}}
@keyframes rotate{from{transform:rotate(0)}to{transform:rotate(360deg)}}
@keyframes glow{0%,100%{text-shadow:0 0 8px rgba(255,179,71,.5)}50%{text-shadow:0 0 22px rgba(255,179,71,.9)}}
@keyframes glowPink{0%,100%{text-shadow:0 0 8px rgba(255,45,120,.4)}50%{text-shadow:0 0 18px rgba(255,45,120,.8)}}
@keyframes glowCyan{0%,100%{text-shadow:0 0 8px rgba(0,212,255,.4)}50%{text-shadow:0 0 18px rgba(0,212,255,.8)}}
@keyframes fadeIn{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:translateY(0)}}
.gold{color:var(--gold)}.green{color:var(--green)}.red{color:var(--red)}.pink{color:var(--pink)}.cyan{color:var(--cyan)}
h2{font-size:15px;letter-spacing:2px;margin-bottom:10px;text-transform:uppercase}
h2.glow-gold{color:var(--gold);text-shadow:0 0 10px rgba(255,179,71,.4)}
h2.glow-pink{color:var(--pink);text-shadow:0 0 10px rgba(255,45,120,.4)}
h2.glow-cyan{color:var(--cyan);text-shadow:0 0 10px rgba(0,212,255,.4)}

/* 1. Status Bar */
#status-bar{text-align:center;padding:18px 14px}
#status-bar .name{font-size:28px;animation:glow 3s ease-in-out infinite;color:var(--gold);font-weight:bold}
#status-bar .online{color:var(--green);font-size:13px;margin-top:6px}
#status-bar .heartbeat{color:var(--dim);font-size:11px;margin-top:4px}

/* 2. Collectors */
#collectors{display:flex;justify-content:space-around;text-align:center;padding:10px 4px}
#collectors .c{font-size:12px;color:var(--gold)}
#collectors .c .icon{font-size:18px;display:block;margin-bottom:2px}
#collectors .c .val{font-weight:bold;font-size:15px}

/* 3. Trinity */
#trinity{text-align:center;padding:16px 8px}
.rings{display:flex;justify-content:center;gap:12px;margin-bottom:12px}
.ring-wrap{position:relative;width:100px;height:100px}
.ring-wrap svg{width:100px;height:100px}
.ring-wrap .ring-bg{fill:none;stroke:#1a1a2e;stroke-width:8}
.ring-wrap .ring-fg{fill:none;stroke-width:8;stroke-linecap:round;transition:stroke-dasharray .8s ease}
.ring-wrap .ring-label{position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);text-align:center;font-size:11px;line-height:1.3}
.ring-wrap .ring-label .num{font-size:22px;font-weight:bold;display:block}
.ring-profit svg{animation:rotate 12s linear infinite}
.ring-love .ring-fg{animation:pulse 2.5s ease-in-out infinite}
.ring-tax .ring-fg{opacity:.8}
#soul-score{font-size:13px;color:var(--dim);margin-top:4px}
#soul-score span{font-size:28px;color:var(--gold);font-weight:bold;display:block;animation:glow 4s ease-in-out infinite}

/* 4. Status Reports */
.report{border-left:3px solid var(--gold);padding:8px 12px;margin-bottom:8px;background:rgba(255,179,71,.04);animation:fadeIn .5s ease}
.report .r-head{color:var(--gold);font-size:12px;font-weight:bold;margin-bottom:4px}
.report .r-body{font-size:13px;color:#ccc;line-height:1.5}

/* 5. Missions */
.mission{margin-bottom:10px;cursor:pointer;border:1px solid var(--border);border-radius:6px;padding:10px;transition:border-color .3s}
.mission:hover{border-color:var(--gold)}
.mission .m-head{display:flex;justify-content:space-between;align-items:center}
.mission .m-name{font-weight:bold;font-size:14px}
.badge{font-size:10px;padding:2px 8px;border-radius:10px;text-transform:uppercase;font-weight:bold}
.badge-active{background:rgba(46,204,113,.2);color:var(--green)}
.badge-building{background:rgba(255,179,71,.2);color:var(--gold)}
.badge-blocked{background:rgba(231,76,60,.2);color:var(--red)}
.badge-completed{background:rgba(0,212,255,.2);color:var(--cyan)}
.badge-live{background:rgba(46,204,113,.25);color:var(--green);border:1px solid rgba(46,204,113,.3)}
.prog-bar{height:6px;background:#12121f;border-radius:3px;margin-top:6px;overflow:hidden}
.prog-fill{height:100%;background:var(--gold);border-radius:3px;transition:width .8s ease}
.prog-pct{font-size:11px;color:var(--dim);margin-top:2px;text-align:right}
.m-details{display:none;margin-top:8px;padding-top:8px;border-top:1px solid var(--border);font-size:12px;color:#aaa}
.m-details.open{display:block;animation:fadeIn .3s ease}
.m-details li{margin:3px 0 3px 16px;list-style:disc}

/* 6. Conversations */
#conv-table{width:100%;border-collapse:collapse;font-size:13px}
#conv-table th{color:var(--gold);text-align:left;padding:4px 6px;font-size:11px;border-bottom:1px solid var(--border)}
#conv-table td{padding:5px 6px;border-bottom:1px solid #15152a}
#conv-table tr:hover{background:rgba(255,179,71,.06)}

/* 7. Command Bridge */
#cmd-input{width:100%;background:#0e0e1a;border:1px solid var(--border);color:#ddd;padding:10px;font-family:Georgia,serif;font-size:14px;border-radius:4px;outline:none;transition:border-color .3s,box-shadow .3s}
#cmd-input:focus{border-color:var(--cyan);box-shadow:0 0 12px rgba(0,212,255,.3)}
.cmd-row{display:flex;gap:6px;margin-top:8px}
#cmd-send{background:var(--panel);color:var(--gold);border:1px solid var(--gold);padding:8px 16px;font-family:Georgia,serif;cursor:pointer;border-radius:4px;transition:all .2s}
#cmd-send:hover{background:var(--gold);color:#000}
#cmd-voice{background:var(--panel);color:var(--red);border:1px solid var(--border);padding:8px 12px;font-family:Georgia,serif;cursor:pointer;border-radius:4px;transition:all .2s}
#cmd-voice.recording{border-color:var(--pink);box-shadow:0 0 12px rgba(255,45,120,.5);animation:pulse 1s infinite}
#cmd-status{font-size:12px;margin-top:6px;min-height:16px}
.cmd-hist{font-size:12px;color:var(--dim);margin-top:8px}
.cmd-hist div{padding:3px 0;border-bottom:1px solid #15152a}

/* 8. Ledger */
.ledger-row{display:flex;justify-content:space-between;font-size:12px;padding:5px 0;border-bottom:1px solid #15152a;flex-wrap:wrap}
.ledger-row .l-date{color:var(--dim);min-width:50px}
.ledger-row .l-action{flex:1;padding:0 6px}
.ledger-row .l-scores{display:flex;gap:8px}

/* 9. Live Feed */
#feed{max-height:180px;overflow-y:auto;font-size:12px;font-family:monospace;background:#0a0a18;padding:8px;border-radius:4px}
#feed::-webkit-scrollbar{width:4px}
#feed::-webkit-scrollbar-thumb{background:var(--border)}
.feed-line .ftime{color:var(--cyan)}

/* 10. Builder */
.builder-row{display:grid;grid-template-columns:1fr 1fr;gap:8px}
.builder-btn{background:var(--panel);border:1px solid var(--border);color:var(--gold);padding:14px 8px;text-align:center;font-family:Georgia,serif;font-size:12px;border-radius:6px;cursor:pointer;transition:all .3s;text-transform:uppercase;letter-spacing:1px}
.builder-btn:hover{border-color:var(--gold);box-shadow:0 0 12px rgba(255,179,71,.3)}
.builder-btn.active{border-color:var(--gold);box-shadow:0 0 16px rgba(255,179,71,.4);background:#1a1520}
.build-form{display:none;margin-top:12px;padding:12px;border:1px solid var(--gold);border-radius:6px;background:#0e0e1a;animation:fadeIn .3s ease}
.build-form.open{display:block}
.build-form h3{color:var(--gold);font-size:13px;margin-bottom:10px;text-transform:uppercase;letter-spacing:1px}
.build-form label{display:block;font-size:11px;color:var(--dim);margin-bottom:3px;text-transform:uppercase;letter-spacing:.5px}
.build-form input,.build-form textarea,.build-form select{width:100%;background:#12121f;border:1px solid var(--border);color:#ddd;padding:8px;font-family:Georgia,serif;font-size:13px;border-radius:4px;margin-bottom:10px;outline:none}
.build-form input:focus,.build-form textarea:focus{border-color:var(--cyan);box-shadow:0 0 6px rgba(0,212,255,.2)}
.build-form textarea{resize:vertical;min-height:60px}
.build-form .form-submit{background:var(--panel);color:var(--gold);border:1px solid var(--gold);padding:10px 20px;font-family:Georgia,serif;cursor:pointer;border-radius:4px;font-size:13px;text-transform:uppercase;letter-spacing:1px;width:100%;transition:all .2s}
.build-form .form-submit:hover{background:var(--gold);color:#000}
.build-form .form-result{margin-top:8px;font-size:12px;min-height:16px}
.build-result-box{background:#0a0a16;border:1px solid var(--green);border-radius:6px;padding:12px;margin-top:10px}
.build-result-box .result-header{display:flex;justify-content:space-between;align-items:center;margin-bottom:8px}
.build-result-box .result-header .result-ts{font-size:10px;color:var(--dim)}
.build-result-box .result-check{color:var(--green);font-size:13px;font-weight:bold;margin-bottom:8px}
.build-result-box pre{background:#080814;border:1px solid var(--border);border-radius:4px;padding:8px;font-size:11px;color:var(--cyan);overflow-x:auto;white-space:pre-wrap;word-break:break-all;font-family:monospace;margin-bottom:8px;max-height:160px;overflow-y:auto}
.copy-btn{background:var(--panel);color:var(--gold);border:1px solid var(--gold);padding:5px 14px;font-family:Georgia,serif;cursor:pointer;border-radius:4px;font-size:11px;transition:all .2s}
.copy-btn:hover{background:var(--gold);color:#000}
.copy-btn.copied{background:var(--green);border-color:var(--green);color:#000}

