PLT_PRESS="$WORKSPACE/web-ecosystem/plt-press"

echo "🔧 PLT Press - Fixing All Buttons & Backends"
echo "============================================"
echo ""

# 1. Start backend server if not running
echo "[1/6] Starting backend API server..."
if ! pgrep -f "dashboard-backend.py" > /dev/null 2>&1; then
    cd "$WORKSPACE"
    nohup python3 dashboard-backend.py > backend.log 2>&1 &
    sleep 2
    echo "✅ Backend started on port 5004"
else
    echo "✅ Backend already running"
fi

