// Fixed sendCommand function
function sendCommand(){
  var input=document.getElementById('cmd-input');
  var status=document.getElementById('cmd-status');
  var txt=input.value.trim();
  if(!txt)return;

  input.value='';
  status.innerHTML='<span style="color:var(--cyan)">⚡ Sending to Profit...</span>';

  // Add to history
  var hist=document.getElementById('cmd-history');
  if(hist){
    hist.innerHTML='<div style="color:var(--gold)">> '+txt+'</div>'+hist.innerHTML;
  }

  // Call backend
  fetch('http://localhost:5004/chat',{
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body:JSON.stringify({message:txt})
  })
  .then(r=>r.json())
  .then(d=>{
    status.innerHTML='<span style="color:var(--green)">✓ '+d.response.replace(/\n/g,'<br>')+'</span>';
  })
  .catch(e=>{
    status.innerHTML='<span style="color:var(--red)">❌ Error: '+e.message+'</span>';
  });
}
console.log('✅ Command Bridge fixed');
CMDEOF
