cat > /tmp/builder-fix.js << 'BUILDEOF'
// Fixed submitBuild function
function submitBuild(type){
  var res=document.getElementById('result-'+type);
  if(!res){
    res=document.createElement('div');
    res.id='result-'+type;
    res.style.marginTop='15px';
    res.style.padding='15px';
    res.style.background='rgba(0,212,255,0.1)';
    res.style.borderRadius='8px';
    var form=document.getElementById('form-'+type);
    if(form) form.appendChild(res);
  }

  res.innerHTML='<span style="color:#00D4FF">⚡ Building with AI...</span>';

  var data={type:type,timestamp:new Date().toISOString()};

  if(type==='book'){
    var t=document.getElementById('book-title');
    var f=document.getElementById('book-framework');
    var m=document.getElementById('book-market');
    var p=document.getElementById('book-price');
    var msg=document.getElementById('book-message');
    data.title=t?t.value:'Untitled';
    data.framework=f?f.value:'PLT';
    data.market=m?m.value:'Entrepreneurs';
    data.price=p?p.value:'49';
    data.message=msg?msg.value:'Complete guide';
  }

  fetch('http://localhost:5004/api/build',{
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body:JSON.stringify({type:type,data:data})
  })
  .then(r=>r.json())
  .then(d=>{
    res.innerHTML='<div style="color:#2ecc71">✅ '+d.result+'</div>';
  })
  .catch(e=>{
    res.innerHTML='<div style="color:#ff6b6b">❌ Error: '+e.message+'</div>';
  });
}

// Fixed toggleBuild
